 using System;
 using System.Collections.Generic;
 using System.Linq;
 using Microsoft.VisualStudio.TestTools.UnitTesting;

 namespace Contoso.Orders;

 [TestClass]
 public sealed class OrderServiceTests
 {
     private readonly OrderService _sut = new();

     private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] entries) =>
         entries.Select(e => new OrderItem { ProductName = e.Name, Price = e.Price, Quantity = e.Qty }).ToList();

     // ──────────────────────────────────────────────
     //  CreateOrder — Happy Path
     // ──────────────────────────────────────────────

     [TestMethod]
     public void CreateOrder_SingleItem_ReturnsOrderWithCorrectProperties()
     {
         // Arrange
         var items = CreateItems(("Widget", 9.99m, 2));

         // Act
         var order = _sut.CreateOrder("cust-1", items);

         // Assert
         Assert.IsNotNull(order);
         Assert.IsFalse(string.IsNullOrWhiteSpace(order.Id));
         Assert.AreEqual("cust-1", order.CustomerId);
         Assert.AreSame(items, order.Items);
         Assert.AreEqual(19.98m, order.Total);
         Assert.IsTrue(order.CreatedAt <= DateTime.UtcNow);
         Assert.IsTrue(order.CreatedAt > DateTime.UtcNow.AddSeconds(-5));
     }

     [TestMethod]
     public void CreateOrder_MultipleItems_CalculatesTotalCorrectly()
     {
         // Arrange
         var items = CreateItems(
             ("Widget", 10.00m, 2),
             ("Gadget", 5.50m, 3),
             ("Gizmo", 7.25m, 1));

         // Act
         var order = _sut.CreateOrder("cust-2", items);

         // Assert — Total = (10*2) + (5.50*3) + (7.25*1) = 20 + 16.50 + 7.25 = 43.75
         Assert.AreEqual(43.75m, order.Total);
         Assert.AreEqual(3, order.Items.Count);
     }

     // ──────────────────────────────────────────────
     //  CreateOrder — Edge Cases
     // ──────────────────────────────────────────────

     [TestMethod]
     public void CreateOrder_ItemWithZeroPrice_ReturnsOrderWithZeroContribution()
     {
         // Arrange
         var items = CreateItems(("FreeItem", 0.00m, 5));

         // Act
         var order = _sut.CreateOrder("cust-3", items);

         // Assert
         Assert.AreEqual(0.00m, order.Total);
     }

     [TestMethod]
     public void CreateOrder_ItemWithLargeQuantity_CalculatesTotalCorrectly()
     {
         // Arrange
         var items = CreateItems(("BulkItem", 1.50m, 100_000));

         // Act
         var order = _sut.CreateOrder("cust-4", items);

         // Assert
         Assert.AreEqual(150_000.00m, order.Total);
     }

     [TestMethod]
     public void CreateOrder_EachCallGeneratesUniqueId()
     {
         // Arrange
         var items = CreateItems(("Widget", 1.00m, 1));

         // Act
         var order1 = _sut.CreateOrder("cust-5", items);
         var order2 = _sut.CreateOrder("cust-5", items);

         // Assert
         Assert.AreNotEqual(order1.Id, order2.Id);
     }

     // ──────────────────────────────────────────────
     //  CreateOrder — Error Cases
     // ──────────────────────────────────────────────

     [TestMethod]
     public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
     {
         // Arrange
         var items = CreateItems(("Widget", 5.00m, 1));

         // Act & Assert
         Assert.ThrowsException<ArgumentNullException>(
             () => _sut.CreateOrder(null!, items));
     }

     [TestMethod]
     public void CreateOrder_NullItems_ThrowsArgumentNullException()
     {
         // Act & Assert
         Assert.ThrowsException<ArgumentNullException>(
             () => _sut.CreateOrder("cust-6", null!));
     }

     [TestMethod]
     public void CreateOrder_EmptyItemsList_ThrowsInvalidOperationException()
     {
         // Arrange
         var items = new List<OrderItem>();

         // Act & Assert
         var ex = Assert.ThrowsException<InvalidOperationException>(
             () => _sut.CreateOrder("cust-7", items));

         Assert.AreEqual("Cannot create an order with no items.", ex.Message);
     }

     // ──────────────────────────────────────────────
     //  CreateOrder — State Transition
     // ──────────────────────────────────────────────

     [TestMethod]
     public void CreateOrder_OrderIsRetrievableViaGetOrderAfterCreation()
     {
         // Arrange
         var items = CreateItems(("Widget", 5.00m, 1));

         // Act
         var created = _sut.CreateOrder("cust-8", items);
         var retrieved = _sut.GetOrder(created.Id);

         // Assert
         Assert.IsNotNull(retrieved);
         Assert.AreEqual(created.Id, retrieved.Id);
         Assert.AreEqual(created.CustomerId, retrieved.CustomerId);
         Assert.AreEqual(created.Total, retrieved.Total);
     }

     // ──────────────────────────────────────────────
     //  GetOrder — Happy Path & Edge Cases
     // ──────────────────────────────────────────────

     [TestMethod]
     public void GetOrder_ExistingOrderId_ReturnsMatchingOrder()
     {
         // Arrange
         var items = CreateItems(("Widget", 12.00m, 1));
         var created = _sut.CreateOrder("cust-9", items);

         // Act
         var result = _sut.GetOrder(created.Id);

         // Assert
         Assert.IsNotNull(result);
         Assert.AreSame(created, result);
     }

     [TestMethod]
     public void GetOrder_NonExistentOrderId_ReturnsNull()
     {
         // Act
         var result = _sut.GetOrder("non-existent-id");

         // Assert
         Assert.IsNull(result);
     }

     // ──────────────────────────────────────────────
     //  GetOrdersByCustomer — Happy Path & Edge Cases
     // ──────────────────────────────────────────────

     [TestMethod]
     public void GetOrdersByCustomer_CustomerWithOneOrder_ReturnsSingleOrder()
     {
         // Arrange
         var items = CreateItems(("Widget", 8.00m, 1));
         var created = _sut.CreateOrder("cust-10", items);

         // Act
         var result = _sut.GetOrdersByCustomer("cust-10");

         // Assert
         Assert.AreEqual(1, result.Count);
         Assert.AreEqual(created.Id, result[0].Id);
     }

     [TestMethod]
     public void GetOrdersByCustomer_CustomerWithMultipleOrders_ReturnsAllOrders()
     {
         // Arrange
         var items1 = CreateItems(("Widget", 5.00m, 1));
         var items2 = CreateItems(("Gadget", 10.00m, 2));
         var order1 = _sut.CreateOrder("cust-11", items1);
         var order2 = _sut.CreateOrder("cust-11", items2);

         // Act
         var result = _sut.GetOrdersByCustomer("cust-11");

         // Assert
         Assert.AreEqual(2, result.Count);
         CollectionAssert.AreEquivalent(
             new[] { order1.Id, order2.Id },
             result.Select(o => o.Id).ToArray());
     }

     [TestMethod]
     public void GetOrdersByCustomer_NoOrdersForCustomer_ReturnsEmptyList()
     {
         // Act
         var result = _sut.GetOrdersByCustomer("unknown-customer");

         // Assert
         Assert.IsNotNull(result);
         Assert.AreEqual(0, result.Count);
     }

     [TestMethod]
     public void GetOrdersByCustomer_MultipleCustomers_ReturnsOnlyMatchingOrders()
     {
         // Arrange
         var items = CreateItems(("Widget", 5.00m, 1));
         _sut.CreateOrder("cust-A", items);
         _sut.CreateOrder("cust-A", items);
         _sut.CreateOrder("cust-B", items);

         // Act
         var resultA = _sut.GetOrdersByCustomer("cust-A");
         var resultB = _sut.GetOrdersByCustomer("cust-B");

         // Assert
         Assert.AreEqual(2, resultA.Count);
         Assert.IsTrue(resultA.All(o => o.CustomerId == "cust-A"));

         Assert.AreEqual(1, resultB.Count);
         Assert.IsTrue(resultB.All(o => o.CustomerId == "cust-B"));
     }

     // ──────────────────────────────────────────────
     //  CreateOrder — DataRow Parameterized Tests
     // ──────────────────────────────────────────────

     [TestMethod]
     [DataRow(1.00, 1, 1.00, DisplayName = "1 × $1.00 = $1.00")]
     [DataRow(2.50, 4, 10.00, DisplayName = "4 × $2.50 = $10.00")]
     [DataRow(0.01, 100, 1.00, DisplayName = "100 × $0.01 = $1.00")]
     [DataRow(99.99, 1, 99.99, DisplayName = "1 × $99.99 = $99.99")]
     public void CreateOrder_VariousPriceAndQuantity_CalculatesExpectedTotal(
         double price, int quantity, double expectedTotal)
     {
         // Arrange
         var items = CreateItems(("Product", (decimal)price, quantity));

         // Act
         var order = _sut.CreateOrder("cust-param", items);

         // Assert
         Assert.AreEqual((decimal)expectedTotal, order.Total);
     }
 }
